package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter_noArg() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withTrailingDelimiter();
        assertNotNull(result);
        assertTrue(result.getTrailingDelimiter());
        // Original should remain unchanged
        assertFalse(original.getTrailingDelimiter());
    }

    @Test
    public void testWithTrailingDelimiter_booleanArg_true() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;

        Method withTrailingDelimiterBool = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterBool.setAccessible(true);

        CSVFormat resultTrue = (CSVFormat) withTrailingDelimiterBool.invoke(original, Boolean.TRUE);
        assertNotNull(resultTrue);
        assertTrue(resultTrue.getTrailingDelimiter());
        assertFalse(original.getTrailingDelimiter());

        CSVFormat resultFalse = (CSVFormat) withTrailingDelimiterBool.invoke(original, Boolean.FALSE);
        assertNotNull(resultFalse);
        assertFalse(resultFalse.getTrailingDelimiter());
        assertFalse(original.getTrailingDelimiter());
    }

    @Test
    public void testWithTrailingDelimiter_booleanArg_idempotent() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;

        Method withTrailingDelimiterBool = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterBool.setAccessible(true);

        CSVFormat first = (CSVFormat) withTrailingDelimiterBool.invoke(original, Boolean.TRUE);
        CSVFormat second = (CSVFormat) withTrailingDelimiterBool.invoke(first, Boolean.TRUE);

        // Should return the same instance if trailingDelimiter already true
        assertSame(first, second);

        CSVFormat third = (CSVFormat) withTrailingDelimiterBool.invoke(original, Boolean.FALSE);
        CSVFormat fourth = (CSVFormat) withTrailingDelimiterBool.invoke(third, Boolean.FALSE);

        // Should return the same instance if trailingDelimiter already false
        assertSame(third, fourth);
    }
}
